PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?mall ?mallLabel ?locationLabel
WHERE {
  ?mall wdt:P31/wdt:P279* wd:Q11315 ;
        wdt:P17 wd:Q30 ;
        wdt:P2046 ?area ;
        rdfs:label ?mallLabel .
  FILTER(LANG(?mallLabel) = "en")
  OPTIONAL {
    ?mall wdt:P276 ?location .
    ?location rdfs:label ?locationLabel .
    FILTER(LANG(?locationLabel) = "en")
  }
}
ORDER BY DESC(?area)
LIMIT 1 OFFSET 1

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?mall ?mallLabel (SAMPLE(?cityLabel) AS ?cityLabel)
WHERE {
  ?mall wdt:P31/wdt:P279* wd:Q11315 ;
        wdt:P17 wd:Q30 ;
        wdt:P2046 ?area ;
        rdfs:label ?mallLabel .
  FILTER(LANG(?mallLabel) = "en")

  # Get city information
  OPTIONAL {
    ?mall wdt:P131+ ?city . 
    ?city rdfs:label ?cityLabel .
    FILTER(LANG(?cityLabel) = "en")
  }

  # Ensure valid numerical area
  FILTER(DATATYPE(?area) = xsd:decimal || DATATYPE(?area) = xsd:double)
}
GROUP BY ?mall ?mallLabel
ORDER BY DESC(xsd:decimal(?area))
LIMIT 1 OFFSET 1

